from vex import Vex
from haystack import component

@component
class VexBrandVerifier:
    def __init__(self):
        self.vex = Vex(api_key="your-vex-key")
        self.verification_suite = self.vex.create_suite([
            self.vex.semantic_similarity(
                reference_field="brand_voice_samples",
                threshold=0.85,
                name="brand_consistency"
            ),
            self.vex.regex_match(
                pattern=r'\b(active|optimistic|approachable)\b',
                name="voice_markers"
            )
        ])

    @component.output_types(verified_content=str, passed=bool)
    def run(self, generated_content: str, brand_samples: list[str]):
        results = self.verification_suite.run({
            "content": generated_content,
            "brand_voice_samples": brand_samples
        })

        if results.passed:
            return {"verified_content": generated_content, "passed": True}
        raise ValueError(f"Brand voice check failed: {results}")

from haystack import component

@component
class VexRetrieverGuard:
    def __init__(self):
        self.vex = Vex(api_key="your-vex-key")
        self.relevance_suite = self.vex.create_suite([
            self.vex.semantic_similarity(
                reference_field="query",
                candidate_field="documents",
                threshold=0.75,
                top_k=3
            )
        ])

    @component.output_types(filtered_documents=list, scores=dict)
    def run(self, query: str, documents: list):
        results = self.relevance_suite.run({
            "query": query,
            "documents": [doc.content for doc in documents]
        })

        relevant_docs = [doc for i, doc in enumerate(documents) 
                        if results.scores[f'documents_{i}'] > 0.75]

        return {
            "filtered_documents": relevant_docs,
            "scores": results.scores
        }

# Add to pipeline
pipeline.add_component("vex_retriever", VexRetrieverGuard())
pipeline.connect("retriever.documents", "vex_retriever.documents")

@component
class VexFinalGuardrail:
    def __init__(self):
        self.vex = Vex(api_key="your-vex-key")
        self.final_suite = self.vex.create_suite([
            self.vex.semantic_similarity(
                reference_field="source_documents",
                threshold=0.8,
                name="factual_accuracy"
            ),
            self.vex.keyword_presence(
                keywords=["AI", "LLM", "content"],  # SEO keywords
                min_count=3
            ),
            self.vex.originality_check(threshold=0.9),
            self.vex.schema_validation(
                schema={"type": "object", "properties": {
                    "title": {"type": "string"},
                    "content": {"minLength": 500}
                }}
            )
        ])

    @component.output_types(final_content=str, verification_report=dict)
    def run(self, content: str, source_docs: list[str]):
        results = self.final_suite.run({
            "content": content,
            "source_documents": source_docs
        })

        return {
            "final_content": content,
            "verification_report": {
                "passed": results.passed,
                "scores": results.scores,
                "failures": results.failures
            }
        }
